## Step 5: Calculate New APP Mass

```
function isNeighbor(cell: Cell, other: Cell): boolean {
  const sameCell = other[0] === cell[0] && other[1] === cell[1];
  return (
    !sameCell &&
    Math.abs(other[0] - cell[0]) <= 1 &&
    Math.abs(other[1] - cell[1]) <= 1
  );
}

export function nextGeneration(cells: Cell[]): Cell[] {
  return cells.filter((cell) => {
    const neighborCount = cells.filter((other) =>
      isNeighbor(cell, other)
    ).length;
    return neighborCount === 2 || neighborCount === 3;
  });
}
```

